  ('medical-tech-moex-16333', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某病人於手術前檢體抗體篩檢為陰性，但自體對照細胞為陽性，直接球蛋白試驗以 anti-IgG 測試為 （2+）。病人最後一次輸血為 9 個月之前，病人並未服用藥物。則該病人紅血球沖出液中所含抗體 為：', '["無抗體存在", "異體抗體", "異體抗體及自體抗體", "自體抗體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 68, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
